class Solution(object):
    def licenseKeyFormatting(self, s, k):
        # split the string at the dashes into a list
        chars = list(s.replace("-", ""))

        # the number of characters in the first group
        n = len(chars)

        # format the first group to have exactly k characters
        chars[0:n % k] = ["".join(chars[0:n % k]).upper()]

        # format the remaining groups to have at most k characters
        for i in range(n % k, len(chars), k):
            chars[i:i+k] = ["".join(chars[i:i+k]).upper()]

        # join everything back together with dashes
        return "".join(chars)

