class Solution(object):
    def canCompleteCircuit(self, gas, cost):
        """
        :type gas: List[int]
        :type cost: List[int]
        :rtype: int
        """
        total_gas = sum(gas)
        total_cost = sum(cost)

        if total_gas < total_cost:
            return -1

        dp = [0] * total_gas
        last = {0: -1}
        remain = 0

        for i in range(len(gas)):
            remain += gas[i] - cost[i]
            if remain < 0:
                remain = 0 - cost[i]
                last[0] = i
            dp[i] = remain + dp[last[remain]]

        if dp[-1] < total_gas:
            return -1

        for i in range(len(gas)):
            if dp[i] == dp[-1]:
                return i

