class Solution(object):
    def toHex(self, num):
        """
        :type num: int
        :rtype: str
        """
        # Dictionary to map hexadecimal digits to their corresponding values
        hex_map = {10:'a', 11:'b', 12:'c', 13:'d', 14:'e', 15:'f'}

        # If the number is negative, find its two's complement
        if num < 0:
            num = num + (1 << 32)

        # Convert the number to hexadecimal string
        hex_str = ""
        while num:
            digit = num % 16
            # If the digit is greater than 'f', replace it with its corresponding letter
            if digit > 9:
                hex_str = hex_map[digit] + hex_str
            else:
                hex_str = str(digit) + hex_str
            num //= 16

        return hex_str

