class Solution(object):
    def findMaximizedCapital(self, k, w, profits, capital):
        projects = []
        for i in range(len(profits)):
            if capital[i] <= w:
                heapq.heappush(projects, (-profits[i], capital[i]))

        result = profit = 0
        while projects and k > 0:
            profit_tmp, capital_tmp = heapq.heappop(projects)
            result += -profit_tmp
            w -= capital_tmp
            k -= 1
            while projects and w >= projects[0][1]:
                temp_profit, temp_capital = heapq.heappop(projects)
                w -= temp_capital
                if temp_capital <= w:
                    heapq.heappush(projects, (temp_profit, temp_capital))
                else:
                    heapq.heappush(projects, (-temp_profit, temp_capital - w))
                    break
            heapq.heapify(projects)
        return result

