class Solution(object):
    def maximumGap(self, nums):
        if len(nums) < 2:
            return 0
        min_, max_ = nums[0], nums[0]
        for num in nums:
            min_ = min(min_, num)
            max_ = max(max_, num)
        bucket_size = (max_-min_)/(len(nums)-1)
        bucket = [[None, None] for _ in range((max_-min_)//bucket_size+1)]
        for num in nums:
            idx = (num-min_)//bucket_size
            if bucket[idx][0] is None:
                bucket[idx][0] = num
            else:
                bucket[idx][1] = num
        max_gap = 0
        for i in range(len(bucket)-1):
            if bucket[i+1][0] is not None:
                max_gap = max(max_gap, bucket[i+1][0]-bucket[i][0])
        return max_gap

