class Solution(object):
    def minSwapsCouples(self, row):
        n = len(row) / 2
        uf = {i: i for i in range(n)}

        def find(x):
            if uf[x]!= x:
                uf[x] = find(uf[x])
            return uf[x]

        def union(x, y):
            uf[find(x)] = find(y)

