    def shortestPalindrome(self, s):
        """
        :type s: str
        :rtype: str
        """
        if not s:
            return ""

        # check if the string is already a palindrome
        if s == s[::-1]:
            return s

        # find the longest prefix of s that is a suffix of the reversed string
        for i in range(len(s)):
            if s[:i] == s[i-1::-1]:
                break

        # append the rest of the reversed string
        return s[i-1::-1] + s

