class Solution(object):
    def isSelfCrossing(self, distance):
        """
        :type distance: List[int]
        :rtype: bool
        """
        # if there is no enough distance to self-cross, return false
        if len(distance) < 3:
            return False

        # if the first or second step is distance[0] or distance[1]
        # then the third step must be greater than distance[2] for self-crossing to occur
        # or the fifth step is distance[3] and the sixth step is greater than distance[0] for self-crossing to occur
        if distance[0] >= distance[2] or distance[1] >= distance[2] or (len(distance) >= 5 and distance[3] == distance[0] and distance[4] > distance[1]):
            return True

        # check for all other cases
        for i in range(2, len(distance)):
            # if the current step is greater than the one step before and the one step before is greater than the two steps before
            # then a self-crossing occurs
            if distance[i] > distance[i-2] and distance[i-1] > distance[i-3]:
                return True
            # if the current step is equal to the one step before
            # then the path might be turning right, but still could be a self-crossing if the distance three steps ago is less than the distance two steps ago
            if distance[i] == distance[i-1]:
                if i >= 4 and distance[i-3] < distance[i-2]:
                    return True

        return False

