        self.val = val
        self.next = next

class Solution(object):
    def mergeKLists(self, lists):
        """
        :type lists: List[ListNode]
        :rtype: ListNode
        """
        import heapq
        dummy = ListNode(0)
        cur = dummy
        heap = []
        # Push all the heads of the lists into the heap
        for l in lists:
            if l:
                heapq.heappush(heap, (l.val, l))
        # Pop smallest element and push the next element from the list
        while heap:
            val, node = heapq.heappop(heap)
            cur.next = ListNode(val)
            cur = cur.next
            if node.next:
                heapq.heappush(heap, (node.next.val, node.next))
