    def minCut(self, s):
        """
        :type s: str
        :rtype: int
        """
        length = len(s)
        # Create a table to record whether substring(i, j) is a palindrome
        table = [[False]*length for _ in range(length)]
        # Every single character is a palindrome, so we initialize table[i][i] as True
        for i in range(length):
            table[i][i] = True
        # Start checking from shorter substrings
        for l in range(2, length+1):
            for i in range(length-l+1):
                j = i+l-1
                # If s[i] == s[j] and substring(i+1, j-1) is a palindrome, then s[i, j] is a palindrome
                if s[i] == s[j] and table[i+1][j-1]:
                    table[i][j] = True
        # Record the minimum cuts needed for a palindrome partitioning of s
        dp = [0]*length
        # For each i in range(length), we check all j that s[j] can cut s[i]
        for l in range(1, length):
            for i in range(length-l):
                j = i+l
                if table[i][j]:
                    dp[j] = min(dp[j], dp[i]+1)
        return dp[-1]

