class Solution(object):
    def medianSlidingWindow(self, nums, k):
        if k > len(nums):
            return []

        smaller, larger = [], []
        res = []

        for i, x in enumerate(nums):
            # First element
            if not smaller or x < -smaller[0]:
                heapq.heappush(smaller, -x)
            else:
                heapq.heappush(larger, x)

            # Balanced
            if len(smaller) > len(larger) + 1:
                heapq.heappush(larger, -heapq.heappop(smaller))
            elif len(smaller) + 1 < len(larger):
                heapq.heappush(smaller, -heapq.heappop(larger))

            if i >= k - 1:
                if len(smaller) == len(larger):
                    median = (-smaller[0] + larger[0]) / 2.0
                else:
                    median = -smaller[0]
                res.append(median)

