    def divide(self, dividend, divisor):
        """
        :type dividend: int
        :type divisor: int
        :rtype: int
        """
        # special cases
        if divisor == 0:
            raise ZeroDivisionError("divisor cannot be zero")
        if dividend == 2**31 - 1 and divisor == 1:
            return 2**31 - 1
        if dividend == -2**31 and divisor == -1:
            return -2**31

        # determine the sign of the result
        sign = 1
        if (dividend < 0 and divisor > 0) or (dividend > 0 and divisor < 0):
            sign = -1

        # convert both dividend and divisor to positive
        dividend = abs(dividend)
        divisor = abs(divisor)

        # binary search
        start, end = 0, 2**31 - 1
        while start + 1 < end:
            mid = start + (end - start) // 2
            if mid / divisor < dividend:
                start = mid
            else:
                end = mid

        # adjust for the situation when we overshoot the target value
        if start / divisor < dividend:
            if sign == 1:
                return end // divisor
            else:
                return -start // divisor

        return sign * start // divisor

