class Solution(object):
    def kInversePairs(self, n, k):
        mod = 10**9 + 7

        # DP table, dp[i][j] is the number of ways to distribute i items into j slots
        dp = [[0]*(k+1) for _ in range(n+1)]

        # initialize dp[0][0] = 1
        dp[0][0] = 1

        for i in range(1, n+1):
            dp[i][0] = 1
            for j in range(1, min(i, k)+1):
                # ways to distribute i items into j slots is the sum of ways to distribute i-1 items into j slots and ways to distribute i-1 items into j-1 slots
                dp[i][j] = (dp[i-1][j] + dp[i-1][j-1]) % mod

        return dp[n][k]

