    def findRedundantDirectedConnection(self, edges):
        n = len(edges)
        parent = list(range(n+1)) # Union-find array. Each index i means node i is the parent of the node (i//2) it points to.
        roots = [0] * (n+1) # Array to keep track of root nodes of each subset.
        for i in range(n):
            if self.union(edges[i], parent): # If we can union the edge's two nodes.
                return edges[i] # This edge is redundant.
            roots[edges[i][1]] = edges[i][0] # Update root for nodes in this edge.
