    def maxSlidingWindow(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: List[int]
        """
        if not nums or k > len(nums) or k <= 0:
            return []

        deque = collections.deque()
        result = []

        for i in range(len(nums)):
            # push the number into the deque and remove the smaller numbers from the head of the deque
            while deque and nums[i] > nums[deque[-1]]:
                deque.pop()
            deque.append(i)

            # remove the numbers at the head of the deque that are not in the window
            if i >= k - 1:
                result.append(nums[deque[0]])
                if i == deque[0]:
                    deque.popleft()
        return result

