import math

class Solution(object):
    def constructRectangle(self, area):
        """
        :type area: int
        :rtype: List[int]
        """
        # Find the square root of the area.
        sqrt_area = math.sqrt(area)
        # If the square root is an integer, then we can return it as both length and width.
        if sqrt_area == int(sqrt_area):
            return [int(sqrt_area), int(sqrt_area)]
        # Otherwise, find the two factors of the area.
        else:
            for i in range(int(sqrt_area), 0, -1):
                if area % i == 0:
                    length = area // i
                    width = i
                    break
            return [length, width]

