        """
        :type s: str
        :type t: str
        :rtype: bool
        """
        # Create a mapping between each character of s and t
        map_s = {}
        map_t = {}

        for char_s, char_t in zip(s, t):
            # If the character is not in the mapping, create a new mapping
            if char_s not in map_s:
                map_s[char_s] = char_t
            if char_t not in map_t:
                map_t[char_t] = char_s
            # If the character is in the mapping, check if the mapping is the same
