    def trap(self, height):
        if not height:
            return 0

        left, right = 0, len(height) - 1
        max_left, max_right = 0, 0
        ans = 0

        while left < right:
            # If the left bar is shorter than the right, we move the left pointer inward
            # Else, we move the right pointer inward
            if height[left] < height[right]:
                if height[left] > max_left:
                    max_left = height[left]
                else:
