    def recoverTree(self, root):
        """
        :type root: TreeNode
        :rtype: None Do not return anything, modify root in-place instead.
        """
        pred = None
        x = None
        y = None

        while root:
            if root.left is None:
                if pred and pred.val > root.val:
                    if x is None:
                        x = pred
                    y = root
                pred = root
                root = root.right
            else:
                pre_left = root.left
                while pre_left.right and pre_left.right!= root:
                    pre_left = pre_left.right
                if not pre_left.right:
                    pre_left.right = root
                    root = root.left
                else:
                    if pred and pred.val > root.val:
                        if x is None:
                            x = pred
                        y = root
                    pred = root
                    root = root.right
        if x and y:
            x.val, y.val = y.val, x.val

