class Solution(object):
    def isAnagram(self, s, t):
        """
        :type s: str
        :type t: str
        :rtype: bool
        """
        # If lengths of s and t are not equal, then they can not be an anagram.
        if len(s)!= len(t):
            return False

        # Create a dictionary to count the frequency of characters in s.
        count = {}
        for letter in s:
            if letter in count:
                count[letter] += 1
            else:
                count[letter] = 1

        # Subtract the frequency of characters in t from that in s.
        for letter in t:
            if letter in count:
                count[letter] -= 1
            else:
                # If letter in t is not in s, then s and t are not anagram.
                return False

        # If all frequencies are zero, then s and t are anagram.
        for k in count:
            if count[k]!= 0:
                return False
        return True

