    def isValidSudoku(self, board):
        rowSet = [set() for _ in range(9)]
        colSet = [set() for _ in range(9)]
        boxSet = [set() for _ in range(9)]

        for i in range(9):
            for j in range(9):
                val = board[i][j]
                if val == '.':
                    continue

                val = int(val)

                # Check row
                if val in rowSet[i]:
                    return False
                rowSet[i].add(val)

                # Check column
                if val in colSet[j]:
                    return False
                colSet[j].add(val)

                # Check 3x3 box
                boxIndex = (i // 3) * 3 + j // 3
                if val in boxSet[boxIndex]:
                    return False
                boxSet[boxIndex].add(val)

        return True

